475→// ---------------------------------------------------------------------------
476→// OpenAI helpers
477→// ---------------------------------------------------------------------------
478→
479→function isRecord(value: unknown): value is Record<string, unknown> {
480→  return Boolean(value) && typeof value === "object" && !Array.isArray(value);
481→}
482→
483→function extractFunctionCalls(payload: ResponsesPayload): FunctionCallItem[] {
484→  if (!Array.isArray(payload.output)) {
485→    return [];
486→  }
487→
488→  return payload.output.flatMap((item) => {
489→    if (!isRecord(item) || item.type !== "function_call") {
490→      return [];
491→    }
492→
493→    const callId = typeof item.call_id === "string" ? item.call_id : null;
494→    const name = typeof item.name === "string" ? item.name : null;
495→    const args = typeof item.arguments === "string" ? item.arguments : null;
496→
497→    if (!callId || !name || !args) {
498→      return [];
499→    }
500→
501→    return [{ arguments: args, callId, name }];
502→  });
503→}
504→
505→function extractAssistantMessage(payload: ResponsesPayload) {
506→  if (typeof payload.output_text === "string" && payload.output_text.trim()) {
507→    return payload.output_text.trim();
508→  }
509→
510→  if (!Array.isArray(payload.output)) {
511→    return "";
512→  }
513→
514→  return payload.output
515→    .flatMap((item) => {
516→      if (
517→        !isRecord(item) ||
518→        item.type !== "message" ||
519→        item.role !== "assistant"
520→      ) {
521→        return [];
522→      }
523→
524→      const content = item.content;
525→      if (!Array.isArray(content)) {
526→        return [];
527→      }
528→
529→      return content.flatMap((entry) => {
530→        if (!isRecord(entry) || entry.type !== "output_text") {
531→          return [];
532→        }
533→
534→        return typeof entry.text === "string" && entry.text.trim()
535→          ? [entry.text.trim()]
536→          : [];
537→      });
538→    })
539→    .join("\n")
540→    .trim();
541→}
542→
543→async function requestOpenAiResponse(
544→  body: Record<string, unknown>,
545→  config: ReturnType<typeof readAdjustmentAiConfig>,
546→) {
547→  const response = await fetch(`${config.openai?.apiBaseUrl}/responses`, {
548→    method: "POST",
549→    headers: {
550→      "Content-Type": "application/json",
551→      Authorization: `Bearer ${config.openai?.apiKey}`,
552→    },
553→    body: JSON.stringify({
554→      model: config.model,
555→      reasoning: { effort: "low" },
556→      store: true,
557→      ...body,
558→    }),
559→    signal: AbortSignal.timeout(config.timeoutMs),
560→  });
561→
562→  if (!response.ok) {
563→    const errorText = await response.text();
564→    throw new AgentUnavailableError(
565→      `Die Live-KI-Antwort war nicht verfügbar (${response.status}). ${errorText.slice(0, 240)}`,
566→    );
567→  }
568→
569→  return (await response.json()) as ResponsesPayload;
570→}
571→
572→// ---------------------------------------------------------------------------
573→// Tool execution with validation
574→// ---------------------------------------------------------------------------
575→
576→function validateEffect(effect: unknown): {
577→  ok: boolean;
578→  data?: Record<string, unknown>;
579→  error?: string;
580→} {
581→  const result = customStyleEffectSchema.safeParse(effect);
582→  if (result.success) {
583→    return { ok: true, data: result.data as Record<string, unknown> };
584→  }
585→
586→  const issues = result.error.issues
587→    .map((i) => `${i.path.join(".")}: ${i.message}`)
588→    .join("; ");
589→  return { ok: false, error: `Effect-Validierung fehlgeschlagen: ${issues}` };
590→}
591→
592→async function executeToolCall(
593→  call: FunctionCallItem,
594→  callbacks: RunAgentTurnInput["callbacks"],
595→  actions: ActionRecord[],
596→): Promise<string> {
597→  let args: Record<string, unknown>;
598→  try {
599→    args = JSON.parse(call.arguments) as Record<string, unknown>;
600→  } catch {
601→    return JSON.stringify({
602→      ok: false,
603→      error: `Ungültige Tool-Argumente: ${call.arguments}`,
604→    });
605→  }
606→
607→  if (call.name === "create_rule") {
608→    const effectValidation = validateEffect(args.effect);
609→    if (!effectValidation.ok) {
610→      return JSON.stringify({ ok: false, error: effectValidation.error });
611→    }
612→
613→    try {
614→      const { ruleId } = await callbacks.onCreateRule({
615→        selector: args.selector as Record<string, unknown>,
616→        effect: effectValidation.data as Record<string, unknown>,
617→        description: String(args.description ?? ""),
618→      });
619→      actions.push({ type: "created", ruleId });
620→      return JSON.stringify({ ok: true, ruleId });
621→    } catch (error) {
622→      return JSON.stringify({
623→        ok: false,
624→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
625→      });
626→    }
627→  }
628→
629→  if (call.name === "update_rule") {
630→    const effectValidation = validateEffect(args.effect);
631→    if (!effectValidation.ok) {
632→      return JSON.stringify({ ok: false, error: effectValidation.error });
633→    }
634→
635→    const ruleId = String(args.ruleId ?? "");
636→
637→    try {
638→      await callbacks.onUpdateRule({
639→        ruleId,
640→        effect: effectValidation.data as Record<string, unknown>,
641→        description:
642→          typeof args.description === "string" ? args.description : undefined,
643→      });
644→      actions.push({ type: "updated", ruleId });
645→      return JSON.stringify({ ok: true, ruleId });
646→    } catch (error) {
647→      return JSON.stringify({
648→        ok: false,
649→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
650→      });
651→    }
652→  }
653→
654→  if (call.name === "delete_rule") {
655→    const ruleId = String(args.ruleId ?? "");
656→
657→    try {
658→      await callbacks.onDeleteRule(ruleId);
659→      actions.push({ type: "deleted", ruleId });
660→      return JSON.stringify({ ok: true, ruleId });
661→    } catch (error) {
662→      return JSON.stringify({
663→        ok: false,
664→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
665→      });
666→    }
667→  }
668→
669→  return JSON.stringify({
670→    ok: false,
671→    error: `Unbekannter Tool-Call: ${call.name}`,
672→  });
673→}
