675→// ---------------------------------------------------------------------------
676→// Main agent turn
677→// ---------------------------------------------------------------------------
678→
679→export async function runAgentTurn(input: RunAgentTurnInput): Promise<{
680→  assistantMessage: string;
681→  actions: ActionRecord[];
682→}> {
683→  const config = readAdjustmentAiConfig();
684→
685→  if (!config.enabled || config.provider !== "openai" || !config.openai) {
686→    throw new AgentUnavailableError(
687→      "Live-KI-Anpassungen sind aktuell nicht konfiguriert. Hinterlege einen OpenAI-Zugang, bevor du diesen Chat nutzt.",
688→    );
689→  }
690→
691→  const actions: ActionRecord[] = [];
692→
693→  const inputMessages = buildInputMessages(input);
694→
695→  let payload = await requestOpenAiResponse(
696→    {
697→      input: inputMessages,
698→      tool_choice: "auto",
699→      tools: buildTools(),
700→    },
701→    config,
702→  );
703→
704→  for (let round = 0; round < MAX_TOOL_ROUNDS; round += 1) {
705→    const functionCalls = extractFunctionCalls(payload);
706→    if (functionCalls.length === 0) {
707→      break;
708→    }
709→
710→    if (!payload.id) {
711→      throw new Error(
712→        "Die KI-Antwort enthält keine Response-ID für den Tool-Loop.",
713→      );
714→    }
715→
716→    const toolOutputs = [];
717→
718→    for (const call of functionCalls) {
719→      const result = await executeToolCall(call, input.callbacks, actions);
720→      toolOutputs.push({
721→        type: "function_call_output",
722→        call_id: call.callId,
723→        output: result,
724→      });
725→    }
726→
727→    payload = await requestOpenAiResponse(
728→      {
729→        input: toolOutputs,
730→        previous_response_id: payload.id,
731→        tool_choice: "auto",
732→        tools: buildTools(),
733→      },
734→      config,
735→    );
736→  }
737→
738→  const rawMessage = extractAssistantMessage(payload);
739→  let assistantMessage: string;
740→
741→  if (rawMessage) {
742→    assistantMessage = rawMessage;
743→  } else if (actions.length > 0) {
744→    assistantMessage = "Die Änderung ist jetzt sichtbar.";
745→  } else {
746→    // The AI returned no text and took no actions — retry once with an
747→    // explicit nudge so the user sees an actual question instead of a
748→    // generic placeholder.
749→    const retryPayload = await requestOpenAiResponse(
750→      {
751→        input: [
752→          ...inputMessages,
753→          {
754→            content: [
755→              {
756→                text: "Du hast gerade keine Antwort gegeben. Bitte stelle dem Nutzer jetzt eine konkrete Rückfrage, damit du eine passende Regel erstellen kannst.",
757→                type: "input_text",
758→              },
759→            ],
760→            role: "user",
761→          },
762→        ],
763→        tool_choice: "none",
764→        tools: buildTools(),
765→      },
766→      config,
767→    );
768→
769→    assistantMessage =
770→      extractAssistantMessage(retryPayload) ||
771→      "Ich konnte die Anfrage nicht verstehen. Kannst du bitte genauer beschreiben, was du ändern möchtest?";
772→  }
773→
774→  return { assistantMessage, actions };
775→}
