472→                      {rule.scope === "format_profile"
473→                        ? rulesLabels.globalScopeNote
474→                        : rulesLabels.defaultRationale}
475→                    </p>
476→                  </div>
477→                  {rule && (
478→                    <pre className="overflow-x-auto rounded bg-zinc-900 px-3 py-2 text-xs text-zinc-300">
479→                      <code>{JSON.stringify(rule, null, 2)}</code>
480→                    </pre>
481→                  )}
482→                </>
